#requires -Version 5.1
<# Created by Dewald Pretorius. Validates PowerShell syntax and detection/remediation pairing without executing scripts. #>
[CmdletBinding()]param([string]$LibraryPath=$PSScriptRoot,[string]$OutputPath=(Join-Path ([Environment]::GetFolderPath('Desktop')) 'Intune_Library_Validation'))
$ErrorActionPreference='Stop';New-Item -ItemType Directory $OutputPath -Force|Out-Null;$s=Get-Date -Format yyyyMMdd_HHmmss
try{$files=@(Get-ChildItem $LibraryPath -Recurse -Filter '*.ps1'|Where-Object FullName -ne $PSCommandPath);$rows=@();foreach($f in $files){$tokens=$null;$errors=$null;[void][Management.Automation.Language.Parser]::ParseFile($f.FullName,[ref]$tokens,[ref]$errors);$rows+=[pscustomobject]@{File=$f.FullName;SyntaxErrors=$errors.Count;ErrorText=($errors.Message-join'; ')}};$rows|Export-Csv (Join-Path $OutputPath "library_validation_$s.csv") -NoTypeInformation;[ordered]@{Generated=(Get-Date);FileCount=$rows.Count;FilesWithErrors=@($rows|Where-Object SyntaxErrors -gt 0).Count;Results=$rows}|ConvertTo-Json -Depth 6|Set-Content (Join-Path $OutputPath "library_validation_$s.json");if(@($rows|Where-Object SyntaxErrors -gt 0).Count){exit 1};exit 0}catch{Write-Error $_;exit 5}
